Bildverdeckung.Front:
{{#Kopfzeile}}<div class="card-box io-native-header">{{Kopfzeile}}</div>{{/Kopfzeile}}
<div style="display: none">{{cloze:Bildverdeckung}}</div>
<div id="err"></div>
<div id="image-occlusion-container">
    {{Bild}}
    <canvas id="image-occlusion-canvas"></canvas>
</div>
<script>
try {
    anki.imageOcclusion.setup();
} catch (exc) {
    document.getElementById("err").innerHTML = `Fehler beim Laden der Bildverdeckung. Ist Ihre Anki-Version aktuell?<br><br>${exc}`;
}
</script>

